FILE *fpAlloc = NULL;
void * my_malloc(int size)
{
  void *ptr;
  //if(fpAlloc == NULL) fpAlloc = fopen ("MemAllocation.txt", "w");
  totalMemAllocation += size;
  ptr = malloc(size);
  if(ptr==NULL)
  {
    TIDL_GLOBAL_REPORT_FATAL_AND_ABORT("Failed to allocate buffer of size %d",size);
  }

  //fprintf(fpAlloc, "Alloc: Ptr: %0x, Size: %0x\n",ptr,size);
  //fflush(fpAlloc);
  return ptr;
}

void my_free(void *ptr)
{
  //fprintf(fpAlloc, "Free: Ptr: %0x\n",ptr);
  //fflush(fpAlloc);
  if (ptr != NULL)
  {
    free(ptr);
    ptr = NULL;
  }
}

bool TIDL_readProtoFromTextFile(const char* fileName, Message* proto)
{
  int32_t           fd;
  bool              success;
  FileInputStream   *input;

  fd = open(fileName, O_RDONLY);
  if (fd == NULL)
  {
    TIDL_GLOBAL_REPORT_FATAL_AND_ABORT("Could not open prototext file %s for reading, check if file exists and is readable", fileName);
  }
  input = new FileInputStream(fd);
  success = google::protobuf::TextFormat::Parse(input, proto);
  delete input;
  close(fd);
  if (!success)
  {
    TIDL_GLOBAL_REPORT_ERROR("google::protobuf::TextFormat::Parse proto file(%s) failed", fileName);
  }
  return success;
}

#define APP_CNN_INTEROP_CAFFE_READ_BINARY_TOTAL_BYTE_LIMIT  2147483647
#define APP_CNN_INTEROP_CAFFE_READ_BINARY_WARNING_THRESHOLD 1073741824

bool TIDL_readProtoFromBinaryFile(const char* fileName, Message* proto)
{
  int                   fd;
  ZeroCopyInputStream   *rawInput;
  CodedInputStream      *codedInput;
  bool                  success;

  fd = open(fileName, O_BINARY);
  if (fd == NULL)
  {
    TIDL_GLOBAL_REPORT_ERROR("Could not open caffe model(%s) for reading, Aborting", fileName);
    return false;
  }

  rawInput = new FileInputStream(fd);
  codedInput = new CodedInputStream(rawInput);

  codedInput->SetTotalBytesLimit(
    APP_CNN_INTEROP_CAFFE_READ_BINARY_TOTAL_BYTE_LIMIT
    );

  success = proto->ParseFromCodedStream(codedInput);
  delete codedInput;
  delete rawInput;
  close(fd);
  if (!success)
  {
    TIDL_GLOBAL_REPORT_ERROR("proto->ParseFromCodedStream: parsing proto file(%s) failed", fileName);
  }
  return success;
}
